const body = $json.body ?? {};
const urls = Array.isArray(body.urls) ? body.urls.filter((url) => typeof url === 'string' && url.trim() !== '') : [];

if (!body.productName || urls.length === 0) {
  throw new Error('competitor 流程需要 productName 與至少一個 urls。');
}

return urls.map((url, index) => ({
  json: {
    workflowType: 'competitor',
    productName: body.productName,
    market: body.market ?? 'TW',
    originalUrl: url,
    scrapeIndex: index + 1,
    firecrawlPayload: {
      url,
      formats: ['markdown']
    }
  }
}));

const items = $input.all();
const body = $('Webhook - Analyze Market').first().json.body ?? {};
const projectName = body.projectName?.trim() || body.productName?.trim() || '未命名專案';
const executionContext = body.executionContext ?? {};

const cleanText = (value) => String(value ?? '')
  .replace(/\s+/g, ' ')
  .trim();

const limitText = (value, maxChars) => {
  const text = cleanText(value);
  if (text.length <= maxChars) return text || '資料不足';
  return text.slice(0, maxChars) + '\n[已裁切：保留前段重點，避免模型輸出被 MAX_TOKENS 截斷]';
};

const sections = items.map((item, index) => {
  const payload = item.json;
  const sourceUrl = payload.originalUrl ?? payload.firecrawlPayload?.url ?? '來源 ' + (index + 1);
  const markdown = payload.data?.markdown ?? payload.markdown ?? payload.content ?? '資料不足';
  return '來源 ' + (index + 1) + '\nURL: ' + sourceUrl + '\n\n' + limitText(markdown, 2200);
});
const scrapedData = limitText(sections.join('\n\n-----\n\n'), 7200);
const productName = body.productName ?? '未提供';
const market = body.market ?? '未提供';
const prompt = '你現在是一位頂尖的 Meta 廣告策略顧問與市場分析師。\n'
  + '請根據以下 <scraped_data> 內的競品網頁文字，產出可直接給商務端閱讀的專業分析。\n\n'
  + '補充執行上下文：\n'
  + '- 專案名稱：' + projectName + '\n'
  + '- 執行階段：第一階段市場洞察\n'
  + '- 本次點數成本：' + (executionContext.pointCost ?? 1) + ' 點\n\n'
  + '任務要求：\n'
  + '1. 提煉競品核心賣點：總結這幾個競品主打的最大優勢。\n'
  + '2. 找出市場痛點：根據頁面內容，推斷消費者未被滿足的渴望、顧慮或抱怨。\n'
  + '3. 多樣化概念建議：針對我的產品提出 5 個完全不同的廣告切入概念，每個概念都必須包含：概念名稱、目標客群、切入痛點、文案方向。\n'
  + '4. 若資料品質不足，不能只停在「資料不足」；必須額外輸出「建議下一步」，具體告訴使用者如何補件，讓系統下次能拿到可分析資料。\n\n'
  + '補充產品資訊：\n'
  + '我的產品名稱：' + productName + '\n'
  + '目標市場：' + market + '\n\n'
  + '輸出格式要求：\n'
  + '- 使用繁體中文。\n'
  + '- 請輸出純文字格式，不要使用 Markdown 符號。\n'
  + '- 禁止使用 #、##、###、*、**、程式碼區塊符號。\n'
  + '- 以清楚段落標題呈現：競品核心賣點、市場痛點、廣告概念建議、建議下一步。\n'
  + '- 目標總字數 1200 到 1800 字；每段完整收尾，不要在句子中途停止。\n\n'
  + '防幻覺機制：\n'
  + '- 嚴格僅使用 <scraped_data> 內的資訊進行分析。\n'
  + '- 絕不可捏造未提及的數據、功能、客戶案例或市佔率。\n'
  + '- 若資料不足，只能做有限推測，並清楚標示推測基礎。\n\n'
  + '<scraped_data>\n' + scrapedData + '\n</scraped_data>';
return [{ json: { workflowType: 'competitor', projectName, prompt, scrapedData, productName, market, executionContext } }];

const body = $('Webhook - Analyze Market').first().json.body ?? {};
const organic = Array.isArray($json.organic) ? $json.organic : [];
const links = organic
  .map((item) => item.link)
  .filter((link) => typeof link === 'string' && link.trim() !== '')
  .slice(0, 3);

if (links.length === 0) {
  throw new Error('Serper 沒有回傳可供 Firecrawl 抓取的連結。');
}

return links.map((url, index) => ({
  json: {
    workflowType: 'concept',
    conceptDesc: body.conceptDesc ?? '',
    market: body.market ?? 'TW',
    searchUrl: url,
    searchIndex: index + 1,
    firecrawlPayload: {
      url,
      formats: ['markdown']
    }
  }
}));

const items = $input.all();
const body = $('Webhook - Analyze Market').first().json.body ?? {};
const projectName = body.projectName?.trim() || body.conceptDesc?.slice(0, 30) || '未命名專案';
const executionContext = body.executionContext ?? {};
const referenceUrls = Array.isArray(body.referenceUrls) ? body.referenceUrls.filter((url) => typeof url === 'string' && url.trim() !== '') : [];

const cleanText = (value) => String(value ?? '')
  .replace(/\s+/g, ' ')
  .trim();

const limitText = (value, maxChars) => {
  const text = cleanText(value);
  if (text.length <= maxChars) return text || '資料不足';
  return text.slice(0, maxChars) + '\n[已裁切：保留前段重點，避免模型輸出被 MAX_TOKENS 截斷]';
};

const sections = items.map((item, index) => {
  const payload = item.json;
  const sourceUrl = payload.searchUrl ?? payload.firecrawlPayload?.url ?? '來源 ' + (index + 1);
  const markdown = payload.data?.markdown ?? payload.markdown ?? payload.content ?? '資料不足';
  const sourceLabel = payload.sourceType === 'reference' ? '參考網站' : '搜尋來源';
  return sourceLabel + ' ' + (index + 1) + '\nURL: ' + sourceUrl + '\n\n' + limitText(markdown, 1800);
});
const scrapedData = limitText(sections.join('\n\n-----\n\n'), 7600);
const conceptDesc = body.conceptDesc ?? '未提供';
const market = body.market ?? '未提供';
const referenceContext = referenceUrls.length > 0
  ? '\n使用者另外提供的參考網址：\n' + referenceUrls.map((url, index) => (index + 1) + '. ' + url).join('\n') + '\n'
  : '\n使用者未另外提供參考網址。\n';
const prompt = '你現在是一位具備頂尖商業嗅覺的 SaaS 產品開發顧問。\n'
  + '請根據以下 <scraped_data> 的市場搜尋結果與參考網站內文，針對我提出的產品概念進行市場驗證與發想。\n\n'
  + '補充執行上下文：\n'
  + '- 專案名稱：' + projectName + '\n'
  + '- 執行階段：第一階段市場洞察\n'
  + '- 本次點數成本：' + (executionContext.pointCost ?? 1) + ' 點\n\n'
  + '我的產品概念：' + conceptDesc + '\n'
  + '目標市場區域：' + market + referenceContext
  + '任務要求：\n'
  + '1. 市場現況總結：目前市場上解決類似問題的方案有哪些，競爭狀態如何。\n'
  + '2. 差異化突圍策略：我的概念在哪裡具有有意義的差異化。\n'
  + '3. 廣告概念矩陣：請為我的產品生成 9 個多樣化廣告概念，必須涵蓋冷受眾、溫受眾、熱受眾三個階段，每階段 3 個概念。\n'
  + '4. 若資料品質不足，不能只停在資料不足，必須提出具體補件與下一步建議。\n'
  + '5. 若使用者提供了參考網站，請明確區分哪些洞察來自搜尋市場資料，哪些洞察來自使用者提供的參考網站。\n\n'
  + '輸出格式要求：\n'
  + '- 使用繁體中文。\n'
  + '- 請輸出純文字格式，不要使用 Markdown 符號。\n'
  + '- 禁止使用 #、##、###、*、**、程式碼區塊符號。\n'
  + '- 以清楚段落標題呈現：市場現況總結、差異化突圍策略、廣告概念矩陣、建議下一步。\n'
  + '- 目標總字數 1400 到 2200 字；每段完整收尾，不要在句子中途停止。\n\n'
  + '防幻覺機制：\n'
  + '- 結論必須基於 <scraped_data> 的客觀內容，不得自行想像地區市佔率或不存在的品牌資料。\n'
  + '- 若資料不足，只能做有限推測，並清楚交代推測基礎。\n\n'
  + '<scraped_data>\n' + scrapedData + '\n</scraped_data>';
return [{ json: { workflowType: 'concept', projectName, prompt, scrapedData, conceptDesc, market, referenceUrls, executionContext } }];

const candidate = $json.candidates?.[0];
const parts = candidate?.content?.parts ?? [];
const markdown = parts.map((part) => part.text).filter(Boolean).join('\n\n');

return [
  {
    json: {
      ok: true,
      type: 'competitor',
      result: markdown || 'Gemini 未回傳內容。',
      raw: $json
    }
  }
];

